import React, { useState } from "react";
import MainPage from "./components/MainPage";
import LoginPage from "./components/LoginPageTemp";
import RegistryPageTemp from "./components/RegistryPageTemp"; 
import axios from 'axios';
import './App.css';
import ForgotPassword from "./components/ForgotPassword";

function App() {
  const [view, setView] = useState('scanner'); 
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);


  const handleUpload = async () => {
    if (!file) return alert("Proszę wybrać zdjęcie!");
    setLoading(true);
    setResult("");

    const formData = new FormData();
    formData.append('file', file);

    try {

      const response = await axios.post('http://localhost:8081/api/scan', formData);
      setResult(response.data);
    } catch (error) {
      setResult("Błąd połączenia z serwerem: " + error.message);
    } finally {
      setLoading(false);
    }
  };




  if (view === 'main') {
    return (
      <MainPage 
        onLogin={() => setView('login')}
        onRegistry={() => setView('registry')} 
      />
    );
  }


  if (view === 'login') {
    return (
      <LoginPage
        onBack={() => setView('main')}
        onRegistry={() => setView('registry')} 
        onLoginSuccess={() => setView('scanner')} 
        onForgotPassword={() => setView('forgot')}
      />
    );
  }


  if (view === 'registry') {
    return (
      <RegistryPageTemp
        onBack={() => setView('main')}
        onLogin={() => setView('login')} 
      />
    );
  }
if (view === 'forgot') {
    return (
      <ForgotPassword 
        onBack={() => setView('login')} 
      />
    );
  }

return (
    <div className="dashboard-wrapper">

        <div className="top-right-nav">
            <button className="nav-btn" onClick={() => alert('Opcje')}>Opcje</button>
            <button className="nav-btn btn-logout" onClick={() => setView('main')}>Wyloguj się</button>
        </div>


        <aside className="sidebar-history">
            <h2 className="sidebar-title">Historia skanów</h2>
            <div className="history-list">
                <div className="history-item">
                    <small>Dziś, 12:45</small>
                    <p>Wynik: Zdrowa skóra</p>
                </div>
                <div className="history-item">
                    <small>05.04.2026</small>
                    <p>Wynik: Do obserwacji</p>
                </div>
            </div>
        </aside>


        <main className="main-scanner-area">
            <div className="scanner-box">
                <h1 style={{marginBottom: '10px', color: '#007bff'}}>MoleCheckerAI</h1>
                <p style={{color: '#aaa', marginBottom: '30px'}}>Prześlij zdjęcie do natychmiastowej analizy</p>

                <div className="file-upload-wrapper">
                    <input 
                        type="file" 
                        id="file-input" 
                        onChange={(e) => setFile(e.target.files[0])} 
                    />
                </div>

                <button 
                    className="analyze-button" 
                    onClick={handleUpload} 
                    disabled={loading}
                    style={{width: '100%', marginTop: '20px'}}
                >
                    {loading ? "Analizowanie..." : "Wyślij do badania"}
                </button>

                {result && (
                    <div className="result-box" style={{marginTop: '25px', background: 'rgba(0,0,0,0.2)', padding: '15px', borderRadius: '12px'}}>
                        <h4 style={{color: '#007bff', margin: '0 0 5px 0'}}>Diagnoza AI:</h4>
                        <p style={{fontSize: '1.2rem', fontWeight: 'bold'}}>{result}</p>
                    </div>
                )}
            </div>
        </main>
    </div>
);
}
export default App;
